using namespace std;

long long solve(vector<long long> robots, vector<long long> distance, vector<long long> walls) {
    int n = robots.size();
    int m = walls.size();
    if (n == 0 || m == 0) return 0;

    // Create a list of robot positions along with their indices for sorting
    vector<pair<long long, int>> robot_indices;
    for (int i = 0; i < n; ++i) {
        robot_indices.emplace_back(robots[i], i);
    }
    // Sort robots based on their positions
    sort(robot_indices.begin(), robot_indices.end());

    // Sort walls
    sort(walls.begin(), walls.end());

    // Precompute the positions of robots in sorted order
    vector<long long> sorted_robots;
    for (auto &p : robot_indices) {
        sorted_robots.push_back(p.first);
    }

    unordered_set<long long> destroyed_walls;

    for (int i = 0; i < n; ++i) {
        long long pos = robot_indices[i].first;
        int idx = robot_indices[i].second;
        long long d = distance[idx];

        // Left shot: [pos - d, pos]
        long long left = pos - d;
        long long right = pos;

        // Find the first robot to the left of current robot (if any)
        auto it_left_robot = lower_bound(sorted_robots.begin(), sorted_robots.end(), pos);
        if (it_left_robot != sorted_robots.begin()) {
            --it_left_robot;
            left = max(left, *it_left_robot + 1); // bullets stop at the robot's right
        }

        // Find walls in [left, right]
        auto wall_start = lower_bound(walls.begin(), walls.end(), left);
        auto wall_end = upper_bound(walls.begin(), walls.end(), right);
        for (auto it = wall_start; it != wall_end; ++it) {
            destroyed_walls.insert(*it);
        }

        // Right shot: [pos, pos + d]
        left = pos;
        right = pos + d;

        // Find the first robot to the right of current robot (if any)
        it_left_robot = upper_bound(sorted_robots.begin(), sorted_robots.end(), pos);
        if (it_left_robot != sorted_robots.end()) {
            right = min(right, *it_left_robot - 1); // bullets stop at the robot's left
        }

        // Find walls in [left, right]
        wall_start = lower_bound(walls.begin(), walls.end(), left);
        wall_end = upper_bound(walls.begin(), walls.end(), right);
        for (auto it = wall_start; it != wall_end; ++it) {
            destroyed_walls.insert(*it);
        }
    }

    return destroyed_walls.size();
}
